SELECT COUNT(DISTINCT LPB.fk_prodbib) AS QTDE_PRODUCOES FROM LATTES_P_PRODBIB LPB JOIN LATTES_PRODBIB PB ON PB.PK = LPB.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LPB.FK_SIAPE WHERE LOWER(PB.TIPO) = LOWER('RESUMO DE TRABALHOS') AND LOWER(PB.NATUREZA) = LOWER('RESUMO') AND LOWER(S.GENERO) = LOWER('MASCULINO') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%letras%') AND LOWER(S.SIGLA_CAMPUS) = LOWER('ITU') AND PB.ANO = '2021'